def validate_alignment_triad(hook_section: dict) -> dict: """Verify Visual + Text + Audio alignment in hook.""" has_visual = bool(hook_section.get("visual_direction")) has_text_overlay = bool(hook_section.get("text_overlay")) has_audio = bool(hook_section.get("audio_script"))
channels_present = sum([has_visual, has_text_overlay, has_audio])
return { "passed": channels_present == 3, "channels_present": channels_present, "missing": [ c for c, present in [ ("visual_direction", has_visual), ("text_overlay", has_text_overlay), ("audio_script", has_audio) ] if not present ], "recommendation": "All 3 channels must convey the same message" }


def validate_dopamine_hits(script_sections: list) -> dict:
    """Check for 2 dopamine hits before 2:30."""
    hits = []
    for section in script_sections:
        if section.get("start_time_seconds", 999) <= 150:  # 2:30
            hits.extend(section.get("dopamine_hits", []))

    return {
        "passed": len(hits) >= 2,
        "hit_count": len(hits),
        "target": "2+ dopamine hits before 2:30",
        "hits_found": hits[:5],
        "recommendation": "Add proof/insight hit" if len(hits) < 2 else None
    }


def validate_two_column_format(script_sections: list) -> dict:
    """Verify every audio line has corresponding visual direction."""
    missing_visuals = []
    for i, section in enumerate(script_sections):
        lines = section.get("lines", [])
        for j, line in enumerate(lines):
            if line.get("audio") and not line.get("visual_direction"):
                missing_visuals.append(f"Section {i+1}, Line {j+1}: Audio without visual")

    return {
        "passed": len(missing_visuals) == 0,
        "lines_checked": sum(len(s.get("lines", [])) for s in script_sections),
        "missing_visual_count": len(missing_visuals),
        "examples": missing_visuals[:3],
        "recommendation": "Every audio line needs a visual direction column"
    }


def validate_proof_front_loaded(script_sections: list) -> dict:
    """Check proof is front-loaded with evidence references."""
    proof_refs = []
    for section in script_sections:
        if section.get("start_time_seconds", 999) <= 150:
            proof_refs.extend(section.get("evidence_refs", []))

    return {
        "passed": len(proof_refs) >= 2,
        "proof_count": len(proof_refs),
        "target": "2-3 proof hits before 2:30",
        "refs": proof_refs,
        "recommendation": "Add EVID references" if len(proof_refs) < 2 else None
    }


def validate_bridge_pattern(script_sections: list) -> dict:
    """Verify a bridge pattern exists between opportunity and offer."""
    bridge_types = ["blind_solution", "problem_quick_fix", "micro_commitment", "identity_gap"]

    bridge_found = None
    for section in script_sections:
        if section.get("bridge_type") in bridge_types:
            bridge_found = section.get("bridge_type")
            break

    return {
        "passed": bridge_found is not None,
        "bridge_type": bridge_found,
        "available_types": bridge_types,
        "recommendation": "Add a bridge pattern between Step 3 and Step 4" if not bridge_found else None
    }


def validate_single_cta(cta_section: dict) -> dict:
    """Check for single dominant CTA with urgency and guarantee."""
    cta_actions = cta_section.get("cta_actions", [])
    has_urgency = cta_section.get("has_real_urgency", False)
    has_guarantee = cta_section.get("has_guarantee_reminder", False)

    issues = []
    if len(cta_actions) == 0:
        issues.append("No CTA action found")
    elif len(cta_actions) > 1:
        issues.append(f"Multiple CTAs: {cta_actions}. Consolidate to single action.")
    if not has_urgency:
        issues.append("No urgency mechanism (ensure it's real if adding)")
    if not has_guarantee:
        issues.append("No guarantee reminder in close")

    return {
        "passed": len(cta_actions) == 1 and has_guarantee,
        "issues": issues,
        "recommendation": "Single CTA + guarantee reminder required"
    }
